import{_ as e,o as t,c as i,ag as r}from"./chunks/framework.eQLvDOR_.js";const p=JSON.parse('{"title":"ai-native-ci-cd","description":"","frontmatter":{"title":"ai-native-ci-cd","concept":"AI 原生 CI/CD","concept_id":"ai-native-ci-cd","aliases":["AI Native CI CD"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Why Your “AI-First” Strategy Is Probably Wrong.md"],"related_concepts":["[[agent-harness-pattern]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/ai-native-ci-cd.md","filePath":"wiki/concepts/ai-native-ci-cd.md","lastUpdated":null}'),c={name:"wiki/concepts/ai-native-ci-cd.md"};function n(o,a,s,l,d,h){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="ai-原生-ci-cd-ai-native-ci-cd" tabindex="-1">AI 原生 CI/CD (AI-Native CI/CD) <a class="header-anchor" href="#ai-原生-ci-cd-ai-native-ci-cd" aria-label="Permalink to &quot;AI 原生 CI/CD (AI-Native CI/CD)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>在以 AI 为主导生产库的架构中，重新设计的决定性交付流水线。其目的是无缝地限制、验证和通过由不可靠 AI 生成的代码变更，确保基础的安全。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>零条件强制验证</strong>：管道包括语法检查、单测、端到端测试，且该流程必须是确定性的，即不能被手工绕过。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Why Your “AI-First” Strategy Is Probably Wrong.html">[Agent_Architecture] Why Your “AI-First” Strategy Is Probably Wrong.md</a>）</li><li><strong>多道护栏</strong>：在合流前应默认引入不同角色专注审查，如安全审查、性能审查。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>如果你使用 Agent，不要让人类成为合并的唯一关卡。人类的价值在于审查意图的“战术或战略风险”，而微观实现应百分百交给硬核通过性的自动化管线。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/agent-harness-pattern.html">agent-harness-pattern</a> — 将此种强制执行的确定性系统当做一种核心的支持平台。</li></ul>',9)])])}const u=e(c,[["render",n]]);export{p as __pageData,u as default};
